@page "/catalog"
@using sv_7fa7b9179cb54babbe1da40524c80d2a.Services
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="row">
    @* Sidebar filters *@
    <div class="col-md-3">
        <div class="border rounded">
            <CatalogFilters Categories="categories"
                            OnFilterApplied="HandleFilterApplied"
                            OnFilterCleared="HandleFilterCleared" />
        </div>
    </div>

    @* Main content *@
    <div class="col-md-9">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (pagedResult is null || pagedResult.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products found. Try adjusting your filters.
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@sortBy"
                            TotalCount="pagedResult.TotalCount"
                            Page="pagedResult.Page"
                            PageSize="pagedResult.PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="pagedResult.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <div class="mt-4">
                <CatalogPagination Page="pagedResult.Page"
                                   TotalCount="pagedResult.TotalCount"
                                   PageSize="pagedResult.PageSize"
                                   OnPageChanged="HandlePageChanged" />
            </div>
        }
    </div>
</div>

@code {
    private List<string> categories = [];
    private PagedResult<Product>? pagedResult;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;
    private bool isLoading = true;
    private string? errorMessage;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = categoriesTask.Result;
            pagedResult = searchTask.Result;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products. {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            pagedResult = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products. {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleFilterCleared()
    {
        currentFilter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        return Task.CompletedTask;
    }
}

